import (
    "context"
    "database/sql"
    entdb "github.com/openmeterio/openmeter/openmeter/ent/db"
    "github.com/openmeterio/openmeter/pkg/framework/entutils"
    "github.com/openmeterio/openmeter/pkg/framework/transaction"
)

type myAdapter struct{ db *entdb.Client }

func (a *myAdapter) Tx(ctx context.Context) (context.Context, transaction.Driver, error) {
    txCtx, cfg, drv, err := a.db.HijackTx(ctx, &sql.TxOptions{ReadOnly: false})
    if err != nil { return nil, nil, fmt.Errorf("hijack tx: %w", err) }
    return txCtx, entutils.NewTxDriver(drv, cfg), nil
}

func (a *myAdapter) WithTx(ctx context.Context, tx *entutils.TxDriver) *myAdapter {
    return &myAdapter{db: entdb.NewTxClientFromRawConfig(ctx, *tx.GetConfig()).Client()}
}

func (a *myAdapter) Self() *myAdapter { return a }

func (a *myAdapter) Create(ctx context.Context, in CreateInput) (*Entity, error) {
    return entutils.TransactingRepo(ctx, a, func(ctx context.Context, tx *myAdapter) (*Entity, error) {
        row, err := tx.db.MyEntity.Create().SetNamespace(in.Namespace).SetName(in.Name).Save(ctx)
        if err != nil { return nil, err }
        return toDomain(row), nil
    })
}
